import java.util.regex.Pattern

class Bad {
    fun isValid(input: String): Boolean {
        val p = Pattern.compile("[A-Z][a-z]+")
        return p.matcher(input).matches()
    }
}

import java.util.regex.Pattern

class Good {
    companion object {
        private val WORD_PATTERN = Pattern.compile("[A-Z][a-z]+")
    }
    fun isValid(input: String): Boolean = WORD_PATTERN.matcher(input).matches()
}
